import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Plugin Registration","description":"Kemoku Plugin Registration","frontmatter":{"title":"Plugin Registration","description":"Kemoku Plugin Registration","weight":20,"extra":{"order":20},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/kemoku/registration"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/kemoku/registration"}],["meta",{"property":"og:title","content":"Plugin Registration"}],["meta",{"property":"og:description","content":"Kemoku Plugin Registration"}],["meta",{"name":"twitter:title","content":"Plugin Registration"}],["meta",{"name":"twitter:description","content":"Kemoku Plugin Registration"}]]},"headers":[],"relativePath":"docs/kemoku/registration.md","filePath":"docs/kemoku/registration.md"}'),r={name:"docs/kemoku/registration.md"};function n(s,e,l,u,c,g){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="plugin-registration" tabindex="-1">Plugin Registration <a class="header-anchor" href="#plugin-registration" aria-label="Permalink to &quot;Plugin Registration&quot;">​</a></h1><p>You need to register your plugin to be able to receive new security and feature updates.</p><hr><h2 id="setup-page" tabindex="-1">Setup Page <a class="header-anchor" href="#setup-page" aria-label="Permalink to &quot;Setup Page&quot;">​</a></h2><p>After activating the plugin you&#39;ll be prompted with a notice to add your product key and configure your review pages.</p><p>Click on <strong>the setup page</strong> link to access the plugin setup interface.</p><hr><h2 id="plugin-registration-1" tabindex="-1">Plugin Registration <a class="header-anchor" href="#plugin-registration-1" aria-label="Permalink to &quot;Plugin Registration&quot;">​</a></h2><p>The setup page includes three main sections. The first section is for plugin registration.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-registration.webp" alt="Kemoku Plugin Registration"></p><h3 id="add-product-key" tabindex="-1">Add Product Key <a class="header-anchor" href="#add-product-key" aria-label="Permalink to &quot;Add Product Key&quot;">​</a></h3><ol><li><strong>Get Your Product Key</strong>: You can find your product key in your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account dashboard</a></li><li><strong>Enter Product Key</strong>: On the setup page, enter the product key you got from your DinoMatic account</li><li><strong>Save</strong>: Click &quot;Save&quot; to register the plugin</li><li><strong>Confirmation</strong>: A message confirming the plugin product key registration will appear</li></ol><h3 id="troubleshooting-registration" tabindex="-1">Troubleshooting Registration <a class="header-anchor" href="#troubleshooting-registration" aria-label="Permalink to &quot;Troubleshooting Registration&quot;">​</a></h3><p>If you get an error that the license key is not correct and the registration fails:</p><ul><li>Make sure there are no white spaces at the beginning or end of the key</li><li>If you have a firewall installed on your server, make sure requests to dinomatic.com are not being blocked</li></ul><hr><h2 id="review-page-slug" tabindex="-1">Review Page Slug <a class="header-anchor" href="#review-page-slug" aria-label="Permalink to &quot;Review Page Slug&quot;">​</a></h2><p>The second section allows you to configure your review pages URL structure.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-review-page-slug.webp" alt="Kemoku Review Page Slug"></p><h3 id="set-reviews-page-slug" tabindex="-1">Set Reviews Page Slug <a class="header-anchor" href="#set-reviews-page-slug" aria-label="Permalink to &quot;Set Reviews Page Slug&quot;">​</a></h3><ol><li><strong>Enter Slug</strong>: Enter the slug you want for your review pages (default: &quot;reviews&quot;)</li><li><strong>Preview URLs</strong>: The setup page shows example URLs based on your slug choice</li><li><strong>Save</strong>: Click &quot;Save&quot; to set the slug</li></ol><p><strong>Example URLs with default slug:</strong></p><ul><li><code>https://your-domain.com/reviews/bet365</code></li><li><code>https://your-domain.com/reviews/bovada</code></li></ul><hr><h2 id="clear-cache" tabindex="-1">Clear Cache <a class="header-anchor" href="#clear-cache" aria-label="Permalink to &quot;Clear Cache&quot;">​</a></h2><p>The third section provides cache management functionality.</p><p><img src="https://media.dinomatic.com/images/docs/kemoku/kemoku-setup-cache.webp" alt="Kemoku Clear Cache"></p><h3 id="clear-plugin-cache" tabindex="-1">Clear Plugin Cache <a class="header-anchor" href="#clear-plugin-cache" aria-label="Permalink to &quot;Clear Plugin Cache&quot;">​</a></h3><ul><li><strong>Clear Cache</strong>: Click &quot;Clear Cache&quot; to remove all cached plugin data</li><li><strong>Use When</strong>: Clear cache if you experience display issues</li></ul>',29)])])}const p=t(r,[["render",n]]);export{h as __pageData,p as default};
